import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void firstArrayIntoSecond() {
        int[] result = new Solution().crossPair(new int[]{2, 7}, new int[]{1, 5}, 8);
        assertArrayEquals(new int[]{1, 0}, result);
    }

    @Test
    void uniquePairWithLargerSecond() {
        int[] result = new Solution().crossPair(new int[]{3, 1, 4}, new int[]{2, 6, 10}, 11);
        assertArrayEquals(new int[]{1, 2}, result);
    }

    @Test
    void pairWithNegatives() {
        int[] result = new Solution().crossPair(new int[]{-5, 0, 8}, new int[]{12, 3}, 11);
        assertArrayEquals(new int[]{2, 1}, result);
    }

    @Test
    void singleElementEach() {
        int[] result = new Solution().crossPair(new int[]{42}, new int[]{58}, 100);
        assertArrayEquals(new int[]{0, 0}, result);
    }
}
